import { workflow, node, trigger, ifElse, newCredential, expr } from '@n8n/workflow-sdk';

// ─── 1. WEBHOOK TRIGGER ─────────────────────────────────────────────────────
const webhookTrigger = trigger({
  type: 'n8n-nodes-base.webhook',
  version: 2.1,
  config: {
    name: 'Supabase Message Webhook',
    parameters: {
      httpMethod: 'POST',
      path: 'claud3-clubhouse',
      responseMode: 'onReceived',
      options: {
        noResponseBody: true
      }
    }
  },
  output: [{
    body: {
      type: 'INSERT',
      table: 'messages',
      record: {
        id: 'abc123',
        created_at: '2026-01-01T00:00:00Z',
        room: 'claude-code-gang',
        nick: 'mike',
        kind: 'user',
        body: 'hey @Claud3 what is up?'
      }
    }
  }]
});

// ─── 2. FILTER: only proceed if @Claud3 mentioned and not from Claud3 ────────
const checkMention = ifElse({
  version: 2.2,
  config: {
    name: 'Is @Claud3 Mentioned?',
    parameters: {
      conditions: {
        options: { caseSensitive: true, leftValue: '', typeValidation: 'loose' },
        conditions: [
          {
            leftValue: expr('{{ $json.body.record.body }}'),
            operator: { type: 'string', operation: 'contains' },
            rightValue: '@Claud3'
          },
          {
            leftValue: expr('{{ $json.body.record.nick }}'),
            operator: { type: 'string', operation: 'notEquals' },
            rightValue: 'Claud3'
          }
        ],
        combinator: 'and'
      }
    }
  }
});

// ─── 3. FETCH RECENT CONTEXT (last 20 msgs from Supabase) ───────────────────
const fetchContext = node({
  type: 'n8n-nodes-base.httpRequest',
  version: 4.4,
  config: {
    name: 'Fetch Recent Messages',
    onError: 'continueErrorOutput',
    parameters: {
      method: 'GET',
      url: expr('{{ $json.body.record.room ? $env.SUPABASE_URL + "/rest/v1/messages?room=eq." + $json.body.record.room + "&order=created_at.desc&limit=20" : $env.SUPABASE_URL + "/rest/v1/messages?room=eq.claude-code-gang&order=created_at.desc&limit=20" }}'),
      authentication: 'genericCredentialType',
      genericAuthType: 'httpHeaderAuth',
      credentials: {
        httpHeaderAuth: newCredential('Supabase Service Key')
      },
      sendHeaders: true,
      specifyHeaders: 'keypair',
      headerParameters: {
        parameters: [
          { name: 'apikey', value: expr('{{ $credentials.httpHeaderAuth.value }}') }
        ]
      }
    }
  },
  output: [[
    { id: 1, created_at: '2026-01-01T00:00:00Z', room: 'claude-code-gang', nick: 'alice', kind: 'user', body: 'hello' },
    { id: 2, created_at: '2026-01-01T00:00:01Z', room: 'claude-code-gang', nick: 'mike', kind: 'user', body: 'hey @Claud3 what is up?' }
  ]]
});

// ─── 4. BUILD CLAUDE PROMPT ──────────────────────────────────────────────────
const buildPrompt = node({
  type: 'n8n-nodes-base.code',
  version: 2,
  config: {
    name: 'Build Claude Prompt',
    parameters: {
      mode: 'runOnceForAllItems',
      language: 'javaScript',
      jsCode: `
// Get the triggering message from the webhook node
const webhookData = $('Supabase Message Webhook').first().json;
const triggerRecord = webhookData.body.record;

// Get fetched messages (array returned by Supabase)
const allItems = $('Fetch Recent Messages').all();
const messages = allItems.length > 0 ? allItems[0].json : [];

// messages from Supabase come back desc (newest first), reverse to chronological
const msgArray = Array.isArray(messages) ? messages : [];
const chronological = [...msgArray].reverse();

// Build transcript string
const transcript = chronological.map(m => \`[\${m.nick}]: \${m.body}\`).join('\\n');

// Final user message for Claude
const userContent = \`Here is the recent chat transcript:\\n\${transcript}\\n\\nNow respond to the latest message that mentioned you. The triggering message was from [\${triggerRecord.nick}]: \${triggerRecord.body}\`;

return [{
  json: {
    userContent,
    triggerNick: triggerRecord.nick,
    triggerBody: triggerRecord.body,
    room: triggerRecord.room
  }
}];
`
    }
  },
  output: [{ userContent: 'Here is the recent chat transcript:\n[mike]: hey @Claud3 what is up?', triggerNick: 'mike', triggerBody: 'hey @Claud3 what is up?', room: 'claude-code-gang' }]
});

// ─── 5. CALL CLAUDE API ──────────────────────────────────────────────────────
const callClaude = node({
  type: 'n8n-nodes-base.httpRequest',
  version: 4.4,
  config: {
    name: 'Call Claude API',
    onError: 'continueErrorOutput',
    parameters: {
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      authentication: 'predefinedCredentialType',
      nodeCredentialType: 'anthropicApi',
      credentials: {
        anthropicApi: { id: 'kBlXWWkHqdKURUJ7', name: 'Anthropic account' }
      },
      sendHeaders: true,
      specifyHeaders: 'keypair',
      headerParameters: {
        parameters: [
          { name: 'anthropic-version', value: '2023-06-01' }
        ]
      },
      sendBody: true,
      contentType: 'json',
      specifyBody: 'json',
      jsonBody: expr('{{ { "model": "claude-sonnet-4-6", "max_tokens": 300, "system": "You are Claud3 — a friendly, terse IRC-style bot in the Claude Code Gang channel, a private chat room for builders at Redwood Services. You live in the channel the way an old IRC regular would. Be helpful and direct, never corporate or verbose. Keep replies to 1-3 short lines max. Occasionally drop a 🌲 when it feels natural but don\'t force it. You can be witty, warm, and a little dry. You\'re here to help, not to perform.", "messages": [{ "role": "user", "content": $json.userContent }] } }}')
    }
  },
  output: [{ content: [{ type: 'text', text: 'What is up! 🌲 All good over here — what do you need?' }], model: 'claude-sonnet-4-6' }]
});

// ─── 6. INSERT CLAUDE REPLY INTO SUPABASE ───────────────────────────────────
const insertReply = node({
  type: 'n8n-nodes-base.httpRequest',
  version: 4.4,
  config: {
    name: 'Insert Claud3 Reply',
    parameters: {
      method: 'POST',
      url: expr('{{ $env.SUPABASE_URL + "/rest/v1/messages" }}'),
      authentication: 'genericCredentialType',
      genericAuthType: 'httpHeaderAuth',
      credentials: {
        httpHeaderAuth: newCredential('Supabase Service Key')
      },
      sendHeaders: true,
      specifyHeaders: 'keypair',
      headerParameters: {
        parameters: [
          { name: 'apikey', value: expr('{{ $credentials.httpHeaderAuth.value }}') },
          { name: 'Prefer', value: 'return=minimal' }
        ]
      },
      sendBody: true,
      contentType: 'json',
      specifyBody: 'json',
      jsonBody: expr('{{ { "room": $("Build Claude Prompt").item.json.room, "nick": "Claud3", "kind": "bot", "body": $json.content[0].text } }}')
    }
  },
  output: [{}]
});

// ─── 7. ERROR FALLBACK INSERT ────────────────────────────────────────────────
const insertFallback = node({
  type: 'n8n-nodes-base.httpRequest',
  version: 4.4,
  config: {
    name: 'Insert Fallback Reply',
    executeOnce: true,
    parameters: {
      method: 'POST',
      url: expr('{{ $env.SUPABASE_URL + "/rest/v1/messages" }}'),
      authentication: 'genericCredentialType',
      genericAuthType: 'httpHeaderAuth',
      credentials: {
        httpHeaderAuth: newCredential('Supabase Service Key')
      },
      sendHeaders: true,
      specifyHeaders: 'keypair',
      headerParameters: {
        parameters: [
          { name: 'apikey', value: expr('{{ $credentials.httpHeaderAuth.value }}') },
          { name: 'Prefer', value: 'return=minimal' }
        ]
      },
      sendBody: true,
      contentType: 'json',
      specifyBody: 'json',
      jsonBody: '{ "room": "claude-code-gang", "nick": "Claud3", "kind": "bot", "body": "🌲 brain hiccup — try me again" }'
    }
  },
  output: [{}]
});

// ─── COMPOSE WORKFLOW ────────────────────────────────────────────────────────
export default workflow('claud3-clubhouse-bot', 'Claud3 — Clubhouse Bot')
  .add(webhookTrigger)
  .to(checkMention
    .onTrue(
      fetchContext
        .onError(insertFallback)
        .to(buildPrompt)
        .to(callClaude
          .onError(insertFallback)
          .to(insertReply)
        )
    )
    .onFalse()
  );
